class Solution {
    public int countDigitOne(int n) {
        if (n < 0) return 0;
        int count = 0;
        long i = 1;
        while (i <= n) {
            long divisor = i * 10;
            long high = n / divisor;
            int current = (n / (int)i) % 10;
            long low = n % i;
            if (current > 1) {
                count += (high + 1) * (int)i;
            } else if (current == 1) {
                count += high * (int)i + (int)low + 1;
            } else {
                count += high * (int)i;
            }
            i *= 10;
        }
        return count;
    }
}

